+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Record<string, unknown>;
+};
+
+export type AspectValue<T extends Aspect> = T extends Aspect<infer Traits>
+    ? UnionToIntersection<TraitRecord<Traits[number]>>
+    : never;
+
+let aspectId = 0;
+
+type UnionToIntersection<T> = (T extends unknown ? (value: T) => void : never) extends (
+    value: infer U
+) => void
+    ? U
+    : never;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<TTraits extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: TTraits
+): Aspect<TTraits> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (trait[$internal].relation || isRelation(trait)) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        const traitSchema = trait.schema as Schema;
+        if (typeof traitSchema === 'function') {
+            throw new Error('Koota: AoS traits cannot be constituents of an aspect.');
+        }
+        for (const field of Object.keys(traitSchema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: Aspect constituent field "${field}" overlaps.`);
+            }
+            fields.add(field);
+            schema[field] = traitSchema[field as keyof typeof traitSchema];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits, schema }) as Aspect<TTraits>;
+}
+
+export function hasAspect(entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => entity.has(trait));
+}
+
+export function getAspect(entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(entity, aspect)) return undefined;
+    return Object.assign({}, ...aspect.traits.map((trait) => entity.get(trait)));
+}
+
+export function splitAspectValue(aspect: Aspect, value: Record<string, unknown>) {
+    return aspect.traits.map((trait) => {
+        const part: Record<string, unknown> = {};
+        for (const field of Object.keys(trait.schema)) {
+            if (field in value) part[field] = value[field];
+        }
+        return [trait, part] as const;
+    });
+}
