+/** Query result path that preserves an aspect as one merged state entry. */
+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+): QueryResult<any> {
+    const results = Object.assign(entities, {
+        readEach(callback: any) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                callback(params.flatMap((param) => isAspect(param) ? [getAspect(entity, param)] : []), entity, i);
+            }
+            return results;
+        },
+        updateEach(callback: any, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const aspects = params.filter(isAspect);
+                const state = aspects.map((aspect) => getAspect(entity, aspect));
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                for (let j = 0; j < aspects.length; j++) {
+                    const aspect = aspects[j];
+                    const value = state[j];
+                    if (!value) continue;
+                    for (const [trait, part] of splitAspectValue(aspect, value)) {
+                        const eid = getEntityId(entity);
+                        const ctx = trait[$internal];
+                        const store = getStore(world, trait);
+                        const shouldDetect = options.changeDetection !== 'never';
+                        const changed = shouldDetect && ctx.fastSetWithChangeDetection(eid, store, part);
+                        if (options.changeDetection === 'always' || changed) setChanged(world, entity, trait);
+                        if (!shouldDetect) ctx.fastSet(eid, store, part);
+                    }
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) { callback([], entities); return results; },
+        select() { return results; },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<any>;
+}
