+function subscribeAspect(
+    world: World,
+    aspect: Aspect,
+    callback: (entity: Entity) => void,
+    type: 'add' | 'remove' | 'change'
+): QueryUnsubscriber {
+    const subscriptions: (() => void)[] = [];
+    for (const trait of aspect.traits) {
+        const ctx = world[$internal];
+        if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);
+        const instance = getTraitInstance(ctx.traitInstances, trait)!;
+        const handler = (entity: Entity) => {
+            // Add runs after insertion; remove runs before removal. Those timings make the
+            // complete/incomplete transition observable without maintaining extra state.
+            if (hasAspect(entity, aspect)) callback(entity);
+        };
+        const set = type === 'add' ? instance.addSubscriptions : type === 'remove' ? instance.removeSubscriptions : instance.changeSubscriptions;
+        set.add(handler);
+        if (type === 'change') ctx.trackedTraits.add(trait);
+        subscriptions.push(() => {
+            set.delete(handler);
+            if (type === 'change' && instance.changeSubscriptions.size === 0) ctx.trackedTraits.delete(trait);
+        });
+    }
+    return () => subscriptions.forEach((unsubscribe) => unsubscribe());
+}
